const functions = require('@google-cloud/functions-framework');
const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');
const { SecretManagerServiceClient } = require('@google-cloud/secret-manager');

const secretClient = new SecretManagerServiceClient();

// Cache for secrets to avoid repeated lookups within the same function instance
let cachedSecrets = null;
let secretsCacheExpiry = 0;
const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes

async function getSecret(secretName) {
  const projectId = process.env.GCP_PROJECT || process.env.GCLOUD_PROJECT;
  const name = `projects/${projectId}/secrets/${secretName}/versions/latest`;

  const [version] = await secretClient.accessSecretVersion({ name });
  return version.payload.data.toString('utf8');
}

async function loadSecrets() {
  const now = Date.now();
  if (cachedSecrets && now < secretsCacheExpiry) {
    return cachedSecrets;
  }

  const [sendgridApiKey, twilioAccountSid, twilioAuthToken, twilioPhoneNumber] =
    await Promise.all([
      getSecret('SENDGRID_API_KEY'),
      getSecret('TWILIO_ACCOUNT_SID'),
      getSecret('TWILIO_AUTH_TOKEN'),
      getSecret('TWILIO_PHONE_NUMBER'),
    ]);

  cachedSecrets = {
    sendgridApiKey,
    twilioAccountSid,
    twilioAuthToken,
    twilioPhoneNumber,
  };
  secretsCacheExpiry = now + CACHE_TTL_MS;

  return cachedSecrets;
}

// Input validation helpers
function validateEmail(email) {
  if (!email || typeof email !== 'string') return false;
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email) && email.length <= 254;
}

function validatePhoneNumber(phone) {
  if (!phone || typeof phone !== 'string') return false;
  // E.164 format
  const phoneRegex = /^\+[1-9]\d{1,14}$/;
  return phoneRegex.test(phone);
}

function sanitizeString(input, maxLength = 1000) {
  if (!input || typeof input !== 'string') return '';
  return input.slice(0, maxLength).trim();
}

function validateMessageType(type) {
  const allowedTypes = ['email', 'sms', 'both'];
  return allowedTypes.includes(type);
}

async function sendEmail(secrets, { to, from, subject, text, html }) {
  sgMail.setApiKey(secrets.sendgridApiKey);

  const msg = {
    to,
    from,
    subject: sanitizeString(subject, 200),
    text: sanitizeString(text, 10000),
  };

  if (html) {
    msg.html = sanitizeString(html, 50000);
  }

  const response = await sgMail.send(msg);
  return {
    success: true,
    channel: 'email',
    statusCode: response[0].statusCode,
    messageId: response[0].headers['x-message-id'] || null,
  };
}

async function sendSMS(secrets, { to, body }) {
  const client = twilio(secrets.twilioAccountSid, secrets.twilioAuthToken);

  const message = await client.messages.create({
    body: sanitizeString(body, 1600),
    from: secrets.twilioPhoneNumber,
    to,
  });

  return {
    success: true,
    channel: 'sms',
    messageSid: message.sid,
    status: message.status,
  };
}

functions.http('sendNotification', async (req, res) => {
  // CORS headers
  const allowedOrigins = (process.env.ALLOWED_ORIGINS || '').split(',').filter(Boolean);
  const origin = req.headers.origin;
  if (allowedOrigins.includes(origin)) {
    res.set('Access-Control-Allow-Origin', origin);
  }
  res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
  res.set('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  res.set('Access-Control-Max-Age', '3600');

  if (req.method === 'OPTIONS') {
    return res.status(204).send('');
  }

  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed. Use POST.' });
  }

  // Verify authorization header (simple shared secret or use IAM in production)
  const authHeader = req.headers.authorization;
  const expectedToken = process.env.FUNCTION_AUTH_TOKEN;
  if (expectedToken) {
    if (!authHeader || !authHeader.startsWith('Bearer ') || authHeader.slice(7) !== expectedToken) {
      return res.status(401).json({ error: 'Unauthorized' });
    }
  }

  // Rate limiting header check (rely on API Gateway / Cloud Endpoints in production)
  const contentType = req.headers['content-type'];
  if (!contentType || !contentType.includes('application/json')) {
    return res.status(400).json({ error: 'Content-Type must be application/json' });
  }

  const {
    type,       // 'email', 'sms', or 'both'
    email,      // { to, from, subject, text, html? }
    sms,        // { to, body }
  } = req.body;

  // Validate message type
  if (!type || !validateMessageType(type)) {
    return res.status(400).json({
      error: 'Invalid or missing "type". Must be one of: email, sms, both',
    });
  }

  // Validate email parameters
  if ((type === 'email' || type === 'both') && email) {
    if (!validateEmail(email.to)) {
      return res.status(400).json({ error: 'Invalid recipient email address' });
    }
    if (!validateEmail(email.from)) {
      return res.status(400).json({ error: 'Invalid sender email address' });
    }
    if (!email.subject || typeof email.subject !== 'string') {
      return res.status(400).json({ error: 'Email subject is required' });
    }
    if (!email.text || typeof email.text !== 'string') {
      return res.status(400).json({ error: 'Email text body is required' });
    }
  } else if (type === 'email' || (type === 'both' && !email)) {
    return res.status(400).json({ error: 'Email parameters are required for email type' });
  }

  // Validate SMS parameters
  if ((type === 'sms' || type === 'both') && sms) {
    if (!validatePhoneNumber(sms.to)) {
      return res.status(400).json({ error: 'Invalid phone number. Use E.164 format (e.g., +1234567890)' });
    }
    if (!sms.body || typeof sms.body !== 'string') {
      return res.status(400).json({ error: 'SMS body is required' });
    }
  } else if (type === 'sms' || (type === 'both' && !sms)) {
    return res.status(400).json({ error: 'SMS parameters are required for sms type' });
  }

  try {
    const secrets = await loadSecrets();
    const results = {};
    const errors = {};

    if (type === 'email' || type === 'both') {
      try {
        results.email = await sendEmail(secrets, email);
      } catch (emailError) {
        console.error('Email sending failed:', {
          error: emailError.message,
          code: emailError.code,
          // Do not log recipient details in production
        });
        errors.email = {
          success: false,
          channel: 'email',
          error: 'Failed to send email',
          code: emailError.code || 'UNKNOWN',
        };
      }
    }

    if (type === 'sms' || type === 'both') {
      try {
        results.sms = await sendSMS(secrets, sms);
      } catch (smsError) {
        console.error('SMS sending failed:', {
          error: smsError.message,
          code: smsError.code,
        });
        errors.sms = {
          success: false,
          channel: 'sms',
          error: 'Failed to send SMS',
          code: smsError.code || 'UNKNOWN',
        };
      }
    }

    const hasErrors = Object.keys(errors).length > 0;
    const hasResults = Object.keys(results).length > 0;

    if (hasErrors && !hasResults) {
      return res.status(500).json({
        success: false,
        message: 'All message deliveries failed',
        errors,
      });
    }

    if (hasErrors && hasResults) {
      return res.status(207).json({
        success: false,
        message: 'Some message deliveries failed',
        results,
        errors,
      });
    }

    return res.status(200).json({
      success: true,
      message: 'All messages sent successfully',
      results,
    });
  } catch (error) {
    console.error('Unexpected error in sendNotification:', {
      message: error.message,
      stack: process.env.NODE_ENV === 'development' ? error.stack : undefined,
    });

    return res.status(500).json({
      success: false,
      error: 'Internal server error. Please try again later.',
    });
  }
});